#!/usr/bin/env node
const { Server } = require("@modelcontextprotocol/sdk/server/index.js");
const { StdioServerTransport } = require("@modelcontextprotocol/sdk/server/stdio.js");
const { CallToolRequestSchema, ListToolsRequestSchema } = require("@modelcontextprotocol/sdk/types.js");
const { spawn } = require("child_process");

const ES_PATH = process.env.ES_PATH || "C:\\mysys\\es.exe";
const ES_WORKSPACE = process.env.ES_WORKSPACE || "";
const workspacePaths = ES_WORKSPACE ? ES_WORKSPACE.split(";").map(p => p.trim()).filter(Boolean) : [];

function executeEverything(args) {
  return new Promise((resolve, reject) => {
    const proc = spawn(ES_PATH, args);
    let stdout = "", stderr = "";
    proc.stdout.on("data", d => { stdout += d.toString(); });
    proc.stderr.on("data", d => { stderr += d.toString(); });
    proc.on("close", code => {
      if (code !== 0 && code !== 1) reject(new Error(`es.exe exited with code ${code}: ${stderr}`));
      else resolve({ stdout, stderr, code });
    });
    proc.on("error", err => reject(new Error(`Failed to execute es.exe: ${err.message}`)));
  });
}

// Run separate es.exe calls per workspace path and merge results.
// This avoids issues with spaces in paths and complex query syntax.
async function executeForWorkspaces(baseArgs, query, maxResults) {
  const allLines = [];
  const seen = new Set();
  for (const wsPath of workspacePaths) {
    const args = [...baseArgs, "-path", wsPath, query];       
    try {
      const result = await executeEverything(args);
      const lines = result.stdout.split(/\r?\n/).filter(Boolean);
      for (const line of lines) {
        const key = line.toLowerCase();
        if (!seen.has(key)) {
          seen.add(key);
          allLines.push(line);
        }
        if (allLines.length >= maxResults) break;
      }
    } catch (e) {
      // skip failing workspace, continue with others
    }
    if (allLines.length >= maxResults) break;
  }
  return allLines.join("\n");
}

const server = new Server({ name: "everything-mcp", version: "1.0.0" }, { capabilities: { tools: {} } });
const wsInfo = workspacePaths.length > 0 ? ` Workspaces: ${workspacePaths.join(", ")}` : "";

server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [{
    name: "search",
    description: `Search files/folders using Everything.${wsInfo}`,
    inputSchema: {
      type: "object",
      properties: {
        query: { type: "string", description: "Search query (Everything syntax)" },
        scope: { type: "string", enum: ["local", "global"], description: "local=workspaces only, global=everywhere", default: "local" },
        maxResults: { type: "number", description: "Max results (default: 50)", default: 50 },
        regex: { type: "boolean", default: false }, caseSensitive: { type: "boolean", default: false },
        wholeWord: { type: "boolean", default: false }, matchPath: { type: "boolean", default: false },
        foldersOnly: { type: "boolean", default: false }, filesOnly: { type: "boolean", default: false },
        sortBy: { type: "string", enum: ["name","path","size","extension","date-created","date-modified","date-accessed"] },
        sortDescending: { type: "boolean", default: false },  
        showSize: { type: "boolean", default: false }, showDateModified: { type: "boolean", default: false },
        parentPath: { type: "string", description: "Search only within this path" },
      },
      required: ["query"],
    },
  }, {
    name: "get_file_info",
    description: "Get detailed file info (size, dates, attributes)",
    inputSchema: {
      type: "object",
      properties: { filename: { type: "string", description: "Full path or filename" } },
      required: ["filename"],
    },
  }],
}));

server.setRequestHandler(CallToolRequestSchema, async (request) => {
  const { name, arguments: args } = request.params;
  try {
    if (name === "search") {
      const { query, scope = "local", maxResults = 50, regex = false, caseSensitive = false,
        wholeWord = false, matchPath = false, foldersOnly = false, filesOnly = false,
        sortBy, sortDescending = false, showSize = false, showDateModified = false, parentPath } = args;
      const esArgs = [];
      if (regex) esArgs.push("-regex");
      if (caseSensitive) esArgs.push("-case");
      if (wholeWord) esArgs.push("-whole-word");
      if (matchPath) esArgs.push("-match-path");
      esArgs.push("-n", String(maxResults));
      if (foldersOnly) esArgs.push("/ad");
      if (filesOnly) esArgs.push("/a-d");
      if (sortBy) { esArgs.push("-sort", sortBy); esArgs.push(sortDescending ? "-sort-descending" : "-sort-ascending"); }   
      if (showSize) esArgs.push("-size");
      if (showDateModified) esArgs.push("-date-modified");    
      // parentPath: use -path for a single specific path     
      if (parentPath) {
        esArgs.push("-path", parentPath, query);
        const result = await executeEverything(esArgs);       
        return { content: [{ type: "text", text: result.stdout || "No results found" }] };
      }
      // local scope with workspace paths: run per-path and merge
      if (scope === "local" && workspacePaths.length > 0) {   
        const merged = await executeForWorkspaces(esArgs, query, maxResults);
        return { content: [{ type: "text", text: merged || "No results found" }] };
      }
      // global scope or no workspace paths: search everywhere
      esArgs.push(query);
      const result = await executeEverything(esArgs);
      return { content: [{ type: "text", text: result.stdout || "No results found" }] };
    } else if (name === "get_file_info") {
      const esArgs = ["-size", "-date-created", "-date-modified", "-date-accessed", "-attributes", "-n", "1", args.filename];
      const result = await executeEverything(esArgs);
      return { content: [{ type: "text", text: result.stdout || "File not found" }] };
    }
    throw new Error(`Unknown tool: ${name}`);
  } catch (error) {
    return { content: [{ type: "text", text: `Error: ${error.message}` }], isError: true };
  }
});

async function main() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  console.error(`Everything MCP server running.${wsInfo}`);   
}
main().catch(e => { console.error("Fatal:", e); process.exit(1); });

