{"instructions_reminder": "LIMIT THE FILE CONTENT TO AT MOST 150 LINES. IF MORE CONTENT NEEDS TO BE ADDED USE THE str-replace-editor TOOL TO EDIT THE FILE AFTER IT HAS BEEN CREATED.", "path": "StrEditor.MCP.pas", "file_content": "Unit StrEditor.MCP;

interface

Uses
  System.SysUtils
, System.Classes
, System.JSON
, StrEditor.CommandLine
, StrEditor.Operations
, StrEditor.Encoding
, StrEditor.BatchProcessor
, StrEditor.Config
, StrEditor.Settings
